import com.google.gson.annotations.SerializedName

// ── Request models ──────────────────────────────────────────────────────────

data class MessagesRequest(
    val model: String,
    val messages: List<Message>,
    @SerializedName("max_tokens") val maxTokens: Int,
    val system: String? = null   // optional system prompt
)

data class Message(
    val role: String,   // "user" or "assistant"
    val content: String // plain text — sufficient for single-turn chat
)

// ── Response models ──────────────────────────────────────────────────────────

data class MessageResponse(
    val id: String,
    val type: String,
    val role: String,
    val content: List<ContentBlock>,
    val model: String,
    @SerializedName("stop_reason") val stopReason: String?,
    val usage: Usage
)

data class ContentBlock(
    val type: String,  // always "text" for non-tool calls
    val text: String
)

data class Usage(
    @SerializedName("input_tokens") val inputTokens: Int,
    @SerializedName("output_tokens") val outputTokens: Int
)

// Helper: extract the assistant's text reply
val MessageResponse.textContent: String
    get() = content.firstOrNull { it.type == "text" }?.text ?: ""

// ── Error model ─────────────────────────────────────────────────────────────

data class ApiError(
    val type: String,
    val error: ErrorDetail
)

data class ErrorDetail(
    val type: String,
    val message: String
)

import retrofit2.Response
import retrofit2.http.Body
import retrofit2.http.Header
import retrofit2.http.POST

interface ClaudeApiService {

    @POST("v1/messages")
    suspend fun createMessage(
        @Header("x-api-key") apiKey: String,
        @Header("anthropic-version") version: String = "2023-06-01",
        @Header("Content-Type") contentType: String = "application/json",
        @Body request: MessagesRequest
    ): Response<MessageResponse>
}

import com.google.gson.Gson
import retrofit2.HttpException
import java.io.IOException

class ClaudeRepository(
    private val api: ClaudeApiService = NetworkModule.claudeApiService,
    private val apiKey: String,   // from your secure config / backend
    private val gson: Gson = Gson()
) {
    companion object {
        private const val MODEL = "claude-opus-4-5"
        private const val MAX_TOKENS = 1024
    }

    suspend fun sendMessage(
        userText: String,
        history: List<Message> = emptyList(),
        systemPrompt: String? = null
    ): Result<String> = runCatching {
        val messages = history + Message(role = "user", content = userText)
        val request = MessagesRequest(
            model = MODEL,
            messages = messages,
            maxTokens = MAX_TOKENS,
            system = systemPrompt
        )
        val response = api.createMessage(apiKey = apiKey, request = request)
        if (response.isSuccessful) {
            response.body()?.textContent
                ?: error("Empty response body")
        } else {
            val errorBody = response.errorBody()?.string()
            val apiError = runCatching {
                gson.fromJson(errorBody, ApiError::class.java)
            }.getOrNull()
            val message = apiError?.error?.message
                ?: "HTTP ${response.code()}: ${response.message()}"
            error(message)
        }
    }.recoverWith { throwable ->
        when (throwable) {
            is IOException -> Result.failure(
                IOException("Network error — check your connection", throwable)
            )
            is HttpException -> Result.failure(
                RuntimeException("HTTP ${throwable.code()}: ${throwable.message()}", throwable)
            )
            else -> Result.failure(throwable)
        }
    }
}

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch

data class ChatMessage(val role: String, val text: String)

sealed class UiState {
    object Idle : UiState()
    object Loading : UiState()
    data class Success(val messages: List<ChatMessage>) : UiState()
    data class Error(val message: String) : UiState()
}

class ChatViewModel(
    private val repository: ClaudeRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow<UiState>(UiState.Idle)
    val uiState: StateFlow<UiState> = _uiState.asStateFlow()

    // Conversation history for multi-turn context
    private val conversationHistory = mutableListOf<Message>()
    private val displayMessages = mutableListOf<ChatMessage>()

    fun sendMessage(userText: String) {
        if (userText.isBlank()) return
        viewModelScope.launch {
            _uiState.value = UiState.Loading
            displayMessages += ChatMessage(role = "user", text = userText)

            val result = repository.sendMessage(
                userText = userText,
                history = conversationHistory.toList()
            )

            result.fold(
                onSuccess = { reply ->
                    // Extend history for next turn
                    conversationHistory += Message(role = "user", content = userText)
                    conversationHistory += Message(role = "assistant", content = reply)
                    displayMessages += ChatMessage(role = "assistant", text = reply)
                    _uiState.value = UiState.Success(displayMessages.toList())
                },
                onFailure = { error ->
                    _uiState.value = UiState.Error(error.message ?: "Unknown error")
                }
            )
        }
    }

    fun clearError() {
        _uiState.value = UiState.Success(displayMessages.toList())
    }
}

import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.unit.dp
import androidx.lifecycle.compose.collectAsStateWithLifecycle

@Composable
fun ChatScreen(viewModel: ChatViewModel) {
    val uiState by viewModel.uiState.collectAsStateWithLifecycle()
    var inputText by remember { mutableStateOf("") }

    Column(modifier = Modifier.fillMaxSize().padding(16.dp)) {
        // Message list
        LazyColumn(
            modifier = Modifier.weight(1f),
            reverseLayout = false
        ) {
            when (val state = uiState) {
                is UiState.Success -> items(state.messages) { msg ->
                    MessageBubble(msg)
                }
                is UiState.Error -> item {
                    ErrorBanner(
                        message = state.message,
                        onDismiss = { viewModel.clearError() }
                    )
                }
                else -> { /* Idle or Loading handled below */ }
            }
        }

        if (uiState is UiState.Loading) {
            LinearProgressIndicator(modifier = Modifier.fillMaxWidth())
        }

        // Input row
        Row(
            modifier = Modifier.fillMaxWidth(),
            verticalAlignment = Alignment.CenterVertically
        ) {
            TextField(
                value = inputText,
                onValueChange = { inputText = it },
                modifier = Modifier.weight(1f),
                placeholder = { Text("Type a message...") },
                enabled = uiState !is UiState.Loading
            )
            Spacer(modifier = Modifier.width(8.dp))
            Button(
                onClick = {
                    viewModel.sendMessage(inputText)
                    inputText = ""
                },
                enabled = inputText.isNotBlank() && uiState !is UiState.Loading
            ) {
                Text("Send")
            }
        }
    }
}

@Composable
private fun MessageBubble(msg: ChatMessage) {
    val isUser = msg.role == "user"
    Row(
        modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp),
        horizontalArrangement = if (isUser) Arrangement.End else Arrangement.Start
    ) {
        Surface(
            shape = MaterialTheme.shapes.medium,
            color = if (isUser) MaterialTheme.colorScheme.primaryContainer
                    else MaterialTheme.colorScheme.surfaceVariant,
            modifier = Modifier.widthIn(max = 280.dp)
        ) {
            Text(
                text = msg.text,
                modifier = Modifier.padding(12.dp),
                style = MaterialTheme.typography.bodyMedium
            )
        }
    }
}

@Composable
private fun ErrorBanner(message: String, onDismiss: () -> Unit) {
    Card(
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.errorContainer
        ),
        modifier = Modifier.fillMaxWidth().padding(vertical = 4.dp)
    ) {
        Row(
            modifier = Modifier.padding(12.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            Text(
                text = message,
                color = MaterialTheme.colorScheme.onErrorContainer,
                modifier = Modifier.weight(1f)
            )
            TextButton(onClick = onDismiss) { Text("Dismiss") }
        }
    }
}

// Parse a 4xx body that Retrofit did NOT auto-throw (Response<T> variant)
fun <T> Response<T>.errorMessage(gson: Gson): String {
    val raw = errorBody()?.string() ?: return "HTTP ${code()}"
    return runCatching {
        gson.fromJson(raw, ApiError::class.java).error.message
    }.getOrDefault(raw.take(200))
}

// Usage in repository:
if (!response.isSuccessful) {
    error(response.errorMessage(gson))
}

import kotlinx.coroutines.test.runTest
import okhttp3.mockwebserver.MockResponse
import okhttp3.mockwebserver.MockWebServer
import org.junit.After
import org.junit.Assert.*
import org.junit.Before
import org.junit.Test
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory

class ClaudeRepositoryTest {

    private val server = MockWebServer()

    private lateinit var repository: ClaudeRepository

    @Before
    fun setUp() {
        server.start()
        val api = Retrofit.Builder()
            .baseUrl(server.url("/"))
            .addConverterFactory(GsonConverterFactory.create())
            .build()
            .create(ClaudeApiService::class.java)
        repository = ClaudeRepository(api = api, apiKey = "test-key")
    }

    @After
    fun tearDown() = server.shutdown()

    @Test
    fun `success response returns assistant text`() = runTest {
        server.enqueue(MockResponse()
            .setResponseCode(200)
            .setBody("""
                {
                  "id": "msg_01",
                  "type": "message",
                  "role": "assistant",
                  "content": [{"type": "text", "text": "Hello!"}],
                  "model": "claude-opus-4-5",
                  "stop_reason": "end_turn",
                  "usage": {"input_tokens": 10, "output_tokens": 5}
                }
            """.trimIndent())
            .addHeader("Content-Type", "application/json")
        )

        val result = repository.sendMessage("Hi")
        assertTrue(result.isSuccess)
        assertEquals("Hello!", result.getOrNull())
    }

    @Test
    fun `401 response returns failure with message`() = runTest {
        server.enqueue(MockResponse()
            .setResponseCode(401)
            .setBody("""
                {"type": "error",
                 "error": {"type": "authentication_error",
                            "message": "Invalid API key"}}
            """.trimIndent())
            .addHeader("Content-Type", "application/json")
        )

        val result = repository.sendMessage("Hi")
        assertTrue(result.isFailure)
        assertTrue(result.exceptionOrNull()?.message?.contains("Invalid API key") == true)
    }

}
